import React from "react";
import { ArrowUpRight, ArrowDownLeft, ArrowLeft, Download } from "lucide-react";
import { jsPDF } from "jspdf";

export default function TransactionHistoryScreen({ transactions = [], onBack, onSelect, darkMode }) {
  const handleDownload = () => {
    const doc = new jsPDF();
    doc.text("Transaction History", 10, 10);

    transactions.forEach((t, index) => {
      doc.text(
        `${index + 1}. ${t.title} - ${t.type.includes("deposit") ? "+" : "-"}₦${t.amount.toLocaleString()} - ${t.date}`,
        10,
        20 + index * 10
      );
    });

    doc.save("transaction-history.pdf");
  };

  return (
    <div className={`min-h-screen px-5 pt-6 pb-24 ${darkMode ? "bg-gray-900 text-gray-100" : "bg-gray-50 text-gray-900"}`}>
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <button onClick={onBack}>
            <ArrowLeft className={`w-6 h-6 ${darkMode ? "text-gray-100" : "text-gray-700"}`} />
          </button>
          <h1 className="text-xl font-semibold">Transactions</h1>
        </div>

        <button onClick={handleDownload} className="p-2 rounded-lg active:scale-95 transition">
          <Download className={`w-5 h-5 ${darkMode ? "text-gray-100" : "text-gray-700"}`} />
        </button>
      </div>

      {/* List */}
      <div className="space-y-4">
        {transactions.map((t) => {
          const isDeposit = t.type.includes("deposit");

          return (
            <div
              key={t.id}
              className={`flex items-center justify-between bg-white p-4 rounded-xl border ${darkMode ? "border-gray-700 bg-gray-800" : "border-gray-100"} shadow-sm cursor-pointer hover:bg-gray-100`}
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center ${
                    isDeposit ? "bg-emerald-100 text-emerald-600" : "bg-red-100 text-red-600"
                  }`}
                >
                  {isDeposit ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                </div>

                <div>
                  <p className="font-semibold">{t.title}</p>
                  <p className="text-xs text-gray-400">{t.date}</p>
                </div>
              </div>

              <span className={`font-bold text-sm ${isDeposit ? "text-emerald-600" : "text-gray-900"}`}>
                {isDeposit ? "+" : "-"}₦{t.amount.toLocaleString()}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
